import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { setLogout } from '../../Redux/Reducer';
import { deleteFcmToken } from '../../CommonUrl';
import { postClientUrlWithToken } from '../../Utils/restUtils';

function Logout() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const authState = useSelector((state) => state.auth);

  useEffect(() => {
    const handleLogout = async () => {
      try {
        if (authState?.userId && authState?.apiUrl) {
          const postData = {
              user_id: authState?.userId,
              device_token: authState?.fcmToken,
          };
          await postClientUrlWithToken(authState?.apiUrl, deleteFcmToken, postData);
        }
      } catch (e) {
          console.error("Error deleting FCM token", e);
      } finally {
        localStorage.removeItem('profileURL');
        localStorage.removeItem('token');
        localStorage.removeItem('auth0_profile');
        localStorage.removeItem('Name');
        localStorage.setItem('authenticated', false);
        localStorage.setItem('login', false);
        dispatch(setLogout());
        navigate('/SignIn');
      }
    };

    handleLogout();
  }, [dispatch, navigate, authState]);

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <h4>Logging out...</h4>
    </div>
  );
}

export default Logout;